import { useState, useRef, useEffect } from 'react';
import { apiCall } from '../services/api';
import PollComponent from './PollComponent';

export default function ChatBox({ messages, currentUser, socket, groupId }) {
    const [text, setText] = useState('');
    const [showPicker, setShowPicker] = useState(false);
    const [showPollBuilder, setShowPollBuilder] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [searchResults, setSearchResults] = useState([]);
    const [selectedRestaurants, setSelectedRestaurants] = useState([]);
    const bottomRef = useRef(null);

    useEffect(() => {
        bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    const formatTime = (dateStr) => {
        if (!dateStr) return '';
        return new Date(dateStr).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    };

    const sendText = () => {
        if (!text.trim() || !socket) return;
        socket.emit('sendMessage', { groupId, text, type: 'text' });
        setText('');
    };

    const searchRestaurants = async () => {
        if (!searchQuery.trim()) return;
        try {
            const res = await apiCall(`/restaurants?search=${encodeURIComponent(searchQuery)}&limit=6`);
            const list = Array.isArray(res.data) ? res.data : res.data?.restaurants || [];
            setSearchResults(list);
        } catch {
            setSearchResults([]);
        }
    };

    const shareRestaurants = () => {
        if (!socket || selectedRestaurants.length === 0) return;
        selectedRestaurants.forEach(r => {
            socket.emit('sendMessage', {
                groupId,
                type: 'restaurant_share',
                restaurantData: {
                    restaurantId: r._id,
                    name: r.name,
                    image: r.images?.[0] || r.image || '',
                    rating: r.averageRating || r.rating || 0,
                    cuisine: r.cuisine || r.cuisineType || '',
                },
            });
        });
        resetPicker();
    };

    const launchPoll = () => {
        if (!socket || selectedRestaurants.length < 2) return;
        socket.emit('createPoll', {
            groupId,
            question: 'Where should we go?',
            restaurantOptions: selectedRestaurants.map(r => ({
                restaurantId: r._id,
                name: r.name,
                image: r.images?.[0] || r.image || '',
                rating: r.averageRating || r.rating || 0,
                cuisine: r.cuisine || r.cuisineType || '',
            })),
        });
        resetPicker();
    };

    const resetPicker = () => {
        setSelectedRestaurants([]);
        setShowPicker(false);
        setShowPollBuilder(false);
        setSearchResults([]);
        setSearchQuery('');
    };

    const toggleSelect = (r) => {
        setSelectedRestaurants(prev =>
            prev.find(x => x._id === r._id) ? prev.filter(x => x._id !== r._id) : [...prev, r]
        );
    };

    return (
        <div className="flex flex-col h-full relative">
            {/* Main Messages Area */}
            <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-4">
                {messages.length === 0 && (
                    <div className="flex justify-center mt-10">
                        <div className="bg-black/5 backdrop-blur-sm px-4 py-2 rounded-full text-gray-500 text-[13px] font-medium shadow-sm">
                            Say hi to start planning! 👋
                        </div>
                    </div>
                )}

                {messages.map((msg, idx) => {
                    const isMe = (msg.sender?._id || msg.sender) === currentUser?._id;
                    const showName = !isMe && (idx === 0 || (messages[idx-1].sender?._id || messages[idx-1].sender) !== (msg.sender?._id || msg.sender));

                    // POLL BUBBLE
                    if (msg.type === 'poll') {
                        return (
                            <div key={msg._id} className="flex justify-center my-6">
                                <PollComponent poll={msg.pollId} socket={socket} currentUser={currentUser} />
                            </div>
                        );
                    }

                    // RESTAURANT SHARE BUBBLE
                    if (msg.type === 'restaurant_share') {
                        const r = msg.restaurantData;
                        return (
                            <div key={msg._id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} mb-3`}>
                                <div className={`flex flex-col max-w-[85%] sm:max-w-[300px]`}>
                                    {showName && <span className="text-[11px] text-gray-500 mb-1 ml-2">{msg.sender?.name}</span>}
                                    <div className={`bg-white rounded-2xl overflow-hidden shadow-sm border border-gray-100 ${isMe ? 'rounded-tr-sm' : 'rounded-tl-sm'}`}>
                                        {r?.image && (
                                            <div className="h-32 w-full bg-gray-200">
                                                <img src={r.image} alt={r.name} className="w-full h-full object-cover" />
                                            </div>
                                        )}
                                        <div className="p-3">
                                            <h4 className="font-bold text-gray-800 text-[15px] leading-tight">{r?.name}</h4>
                                            <p className="text-xs text-gray-500 mt-1 flex items-center gap-1.5">
                                                <span>{r?.cuisine || 'Restaurant'}</span>
                                                <span>•</span>
                                                <span className="flex items-center text-amber-500 font-medium">
                                                    ★ {Number(r?.rating || 0).toFixed(1)}
                                                </span>
                                            </p>
                                        </div>
                                    </div>
                                    <div className={`text-[10px] mt-1 text-gray-400 ${isMe ? 'text-right mr-1' : 'ml-1'}`}>
                                        {formatTime(msg.createdAt)}
                                    </div>
                                </div>
                            </div>
                        );
                    }

                    // NORMAL TEXT BUBBLE
                    return (
                        <div key={msg._id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                            <div className={`flex flex-col max-w-[75%] sm:max-w-[65%] ${isMe ? 'items-end' : 'items-start'}`}>
                                {showName && (
                                    <span className="text-[11px] text-gray-500 mb-1 ml-2 font-medium">{msg.sender?.name}</span>
                                )}
                                <div className={`relative px-4 py-2.5 text-[15px] shadow-sm flex flex-col ${
                                    isMe 
                                        ? 'bg-blue-500 text-white rounded-2xl rounded-tr-sm' 
                                        : 'bg-white text-gray-800 rounded-2xl rounded-tl-sm border border-gray-100'
                                }`}>
                                    <span className="leading-snug break-words">{msg.text}</span>
                                    <span className={`text-[10px] mt-1 self-end translate-y-0.5 ${isMe ? 'text-blue-100' : 'text-gray-400'}`}>
                                        {formatTime(msg.createdAt)}
                                    </span>
                                </div>
                            </div>
                        </div>
                    );
                })}
                <div ref={bottomRef} className="h-1" />
            </div>

            {/* Restaurant Picker Overlay Tool */}
            {(showPicker || showPollBuilder) && (
                <div className="absolute bottom-full left-0 right-0 bg-white/95 backdrop-blur-md border-t border-gray-200 p-4 shadow-[0_-10px_25px_rgba(0,0,0,0.05)] z-10 transition-all duration-300">
                    <div className="max-w-2xl mx-auto">
                        {showPicker && !showPollBuilder && (
                            <>
                                <div className="flex items-center gap-2 mb-4">
                                    <div className="flex-1 relative">
                                        <svg className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                                        <input
                                            type="text"
                                            value={searchQuery}
                                            onChange={e => setSearchQuery(e.target.value)}
                                            onKeyDown={e => e.key === 'Enter' && searchRestaurants()}
                                            placeholder="Search a restaurant to share..."
                                            className="w-full bg-gray-100 border-none rounded-full py-2.5 pl-10 pr-4 text-sm focus:ring-2 focus:ring-blue-500 outline-none transition-shadow"
                                        />
                                    </div>
                                    <button onClick={searchRestaurants} className="bg-gray-800 text-white px-4 py-2.5 rounded-full text-sm font-medium hover:bg-gray-700 transition">Search</button>
                                </div>

                                <div className="max-h-48 overflow-y-auto rounded-xl space-y-1 pr-1 custom-scrollbar">
                                    {searchResults.length === 0 && searchQuery && <p className="text-center text-sm text-gray-500 py-4">No results found.</p>}
                                    {searchResults.map(r => {
                                        const isSelected = selectedRestaurants.some(x => x._id === r._id);
                                        return (
                                            <div key={r._id} onClick={() => toggleSelect(r)} className={`flex items-center gap-3 p-2 rounded-xl cursor-pointer transition-colors border max-w-full ${isSelected ? 'bg-blue-50 border-blue-200' : 'bg-transparent border-transparent hover:bg-gray-50'}`}>
                                                <div className="w-10 h-10 rounded-lg bg-gray-200 overflow-hidden shrink-0">
                                                    {(r.images?.[0] || r.image) && <img src={r.images?.[0] || r.image} alt="" className="w-full h-full object-cover" />}
                                                </div>
                                                <div className="flex-1 min-w-0">
                                                    <h5 className="text-sm font-semibold text-gray-800 truncate">{r.name}</h5>
                                                    <p className="text-[11px] text-gray-500 truncate">{r.cuisine}</p>
                                                </div>
                                                {isSelected && <div className="w-5 h-5 rounded-full bg-blue-500 text-white flex items-center justify-center shrink-0"><svg className="w-3.5 h-3.5" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg></div>}
                                            </div>
                                        );
                                    })}
                                </div>

                                {selectedRestaurants.length > 0 && (
                                    <div className="flex items-center gap-3 mt-4 pt-3 border-t border-gray-100">
                                        <button onClick={shareRestaurants} className="flex-1 bg-blue-500 text-white py-2.5 rounded-xl text-sm font-semibold hover:bg-blue-600 transition-colors shadow-sm">
                                            Send Directly ({selectedRestaurants.length})
                                        </button>
                                        {selectedRestaurants.length >= 2 && (
                                            <button onClick={() => { setShowPollBuilder(true); setShowPicker(false); }} className="flex-1 bg-white border border-blue-500 text-blue-600 py-2.5 rounded-xl text-sm font-semibold hover:bg-blue-50 transition-colors">
                                                Create Poll instead
                                            </button>
                                        )}
                                        <button onClick={resetPicker} className="px-4 py-2 text-sm text-gray-500 hover:text-gray-700">Cancel</button>
                                    </div>
                                )}
                            </>
                        )}

                        {showPollBuilder && (
                            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                                <h4 className="text-gray-800 font-bold mb-3">Launch Poll with these {selectedRestaurants.length} options?</h4>
                                <div className="flex flex-wrap gap-2 mb-5">
                                    {selectedRestaurants.map(r => (
                                        <span key={r._id} className="bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-[13px] font-medium border border-blue-200">
                                            {r.name}
                                        </span>
                                    ))}
                                </div>
                                <div className="flex gap-3">
                                    <button onClick={launchPoll} className="flex-1 bg-blue-500 text-white rounded-xl py-3 font-semibold text-sm hover:bg-blue-600 shadow-md">
                                        Launch Poll into Chat 🚀
                                    </button>
                                    <button onClick={resetPicker} className="px-6 py-3 bg-gray-100 text-gray-600 rounded-xl font-medium text-sm hover:bg-gray-200">
                                        Cancel
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Input Bar */}
            <div className="bg-[#F4F4F5] px-4 py-3 pb-safe border-t border-gray-300/60 z-20">
                <div className="flex items-end gap-2 max-w-4xl mx-auto">
                    {/* Plus / Features Menu Button */}
                    <button 
                        onClick={() => { setShowPicker(v => !v); setShowPollBuilder(false); }}
                        className={`p-2.5 rounded-full transition-colors flex shrink-0 ${showPicker || showPollBuilder ? 'bg-blue-100 text-blue-600' : 'text-gray-500 hover:bg-gray-200'}`}
                        title="Share a restaurant or poll"
                    >
                        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                    </button>

                    {/* Text Input Container */}
                    <div className="flex-1 bg-white rounded-2xl border border-gray-300 shadow-sm flex items-center px-3 py-1.5 focus-within:border-blue-400 focus-within:ring-2 focus-within:ring-blue-100 transition-all">
                        <button className="text-gray-400 hover:text-gray-600 p-1 mr-1">
                            {/* Emoji Icon placeholder */}
                            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.828 14.828a4 4 0 01-5.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                        </button>
                        <input
                            type="text"
                            value={text}
                            onChange={e => setText(e.target.value)}
                            onKeyDown={e => e.key === 'Enter' && sendText()}
                            placeholder="Type a message..."
                            className="w-full bg-transparent border-none focus:outline-none py-1.5 text-[15px] text-gray-800 placeholder-gray-400 font-sans"
                        />
                    </div>

                    {/* Send Button */}
                    <button 
                        onClick={sendText} 
                        disabled={!text.trim()} 
                        className={`p-2.5 rounded-full flex items-center justify-center shrink-0 transition-transform ${text.trim() ? 'bg-blue-500 text-white shadow-md hover:bg-blue-600 active:scale-95' : 'bg-transparent text-transparent pointer-events-none'}`}
                    >
                        <svg className="w-5 h-5 translate-x-[2px] -translate-y-[1px]" viewBox="0 0 20 20" fill="currentColor"><path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" /></svg>
                    </button>
                </div>
            </div>
        </div>
    );
}
